import numpy as np
import sounddevice as sd
import tkinter as tk
from tkinter import font as tkfont
import threading
import time

# Sample rate
SAMPLE_RATE = 44100

# C4 frequency
C4_FREQ = 261.63

# 12th root of 2
SEMITONE = 2 ** (1 / 12)


def note_freq(base_freq, semitones):
    """Calculate frequency given base frequency and number of semitones."""
    return base_freq * (SEMITONE ** semitones)


# C Major scale intervals (semitones from C4)
# C D E F G A B C
C_MAJOR_SEMITONES = [0, 2, 4, 5, 7, 9, 11, 12]
C_MAJOR_NAMES = ['C4', 'D4', 'E4', 'F4', 'G4', 'A4', 'B4', 'C5']

# C Harmonic Minor scale intervals (semitones from C4)
# C D Eb F G Ab B C
C_HARM_MINOR_SEMITONES = [0, 2, 3, 5, 7, 8, 11, 12]
C_HARM_MINOR_NAMES = ['C4', 'D4', 'Eb4', 'F4', 'G4', 'Ab4', 'B4', 'C5']


def generate_tone(frequency, duration, sample_rate=SAMPLE_RATE, amplitude=0.5):
    """Generate a sine wave tone with fade in/out to avoid clicks."""
    t = np.linspace(0, duration, int(sample_rate * duration), endpoint=False)
    wave = amplitude * np.sin(2 * np.pi * frequency * t)

    # Apply fade in/out (10ms each)
    fade_samples = int(0.01 * sample_rate)
    fade_in = np.linspace(0, 1, fade_samples)
    fade_out = np.linspace(1, 0, fade_samples)

    if len(wave) > 2 * fade_samples:
        wave[:fade_samples] *= fade_in
        wave[-fade_samples:] *= fade_out

    # Make stereo (2D array with shape (samples, 2))
    stereo_wave = np.column_stack([wave, wave])
    return stereo_wave.astype(np.float32)


def play_scale(semitones, note_names, note_duration=0.6, highlight_callback=None):
    """Play a scale given semitone intervals from C4."""
    for i, semitones_val in enumerate(semitones):
        freq = note_freq(C4_FREQ, semitones_val)
        print(f"Playing {note_names[i]}: {freq:.2f} Hz")

        # Highlight the note in the UI
        if highlight_callback:
            highlight_callback(i)

        # Generate and play the tone
        tone = generate_tone(freq, note_duration)
        sd.play(tone, samplerate=SAMPLE_RATE)
        sd.wait()

        # Small gap between notes
        time.sleep(0.05)

    # Clear highlight
    if highlight_callback:
        highlight_callback(-1)


