    def highlight_major(self, index):
        """Highlight a note in the major scale display."""
        for i, lbl in enumerate(self.major_labels):
            if i == index:
                lbl.config(bg='#ffeb3b', fg='#1a1a2e')
            else:
                lbl.config(bg='#0d47a1', fg='white')
        self.root.update_idletasks()

